class Solution {
    public int numberOfWays(int n, int x, int y) {
        final int MOD = (int) 1e9 + 7;
        long[][] dp = new long[n + 1][x + 1];
        dp[0][0] = 1;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= Math.min(i, x); j++) {
                dp[i][j] = (dp[i - 1][j - 1] * j + dp[i - 1][j] * (j - 1)) % MOD;
            }
            for (int j = x; j > 0; j--) {
                dp[i][j] = (dp[i][j] + dp[i][j + 1]) % MOD;
            }
        }

        long res = 0;
        for (int j = 1; j <= x; j++) {
            res = (res + dp[n][j]) % MOD;
        }

        return (int) ((res * y) % MOD);
    }
}
